#include <stdio.h>
#include <errno.h>
#include <string.h>
#include <fcntl.h>
#include <unistd.h>
int main(void) {
    int fd = open("/tmp/clings_nonexistent_file_xyz.txt", O_RDONLY);
    if (fd == -1) {
        printf("open failed: errno=%d (%s)\n", errno, strerror(errno));
    } else {
        printf("open succeeded (unexpected)\n");
        close(fd);
    }
    printf("ENOENT=%d\n", ENOENT);
    return 0;
}

